import re

def extract_bbox_map_values(text):
    """
    Extract all numeric values following "bbox_mAP:" from the text.
    
    Args:
        text (str): The text content to parse.
        
    Returns:
        list: A list of extracted values (float type).
    """
    # Use regex to match all occurrences of the pattern
    pattern = r"bbox_mAP:\s*([\d.]+)"
    matches = re.findall(pattern, text)
    
    # Convert matched strings to float
    results = []
    for match in matches:
        try:
            # Convert and preserve original precision
            num = float(match)
            results.append(num)
        except ValueError:
            # Ignore non-numeric content (should not happen, but handle safely)
            continue
    
    return results

